patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index d824c40c401d..b17edf42260b 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9801,7 +9801,15 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
                       return std::min(S, I);
                     }),
                 EltsPerVector);
-            Indices.push_back(OffsetReg1 % NumElts);
+            // Ensure the extracted subvector start index does not exceed the
+            // padded vector boundary. The cost model later asserts that
+            // (Start + EltsPerVector) <= alignTo(NumElts, EltsPerVector).
+            unsigned PaddedSize = alignTo(NumElts, EltsPerVector);
+            unsigned SubIdx = OffsetReg1 % NumElts;
+            SubIdx = alignDown(SubIdx, EltsPerVector);
+            if (SubIdx + EltsPerVector > PaddedSize)
+              SubIdx = PaddedSize - EltsPerVector; // Clamp to last valid start.
+            Indices.push_back(SubIdx);
           }
           Idx = I - OffsetReg1;
         }

